 50→>;
 51→
 52→const PAGE_SIZE = 10;
 53→
 54→export function HomeFeedScreen({navigation}: Props) {
 55→  const {user, session} = useAuth();
 56→  const {colors} = useTheme();
 57→  const token = session?.access_token ?? '';
 58→  const [refreshing, setRefreshing] = useState(false);
 59→  const [feedTab, setFeedTab] = useState<FeedTab>('all');
 60→  const [forYouOffset, setForYouOffset] = useState(0);
 61→  const [commentModal, setCommentModal] = useState<{postId: string; receiverId?: string; commentCount: number} | null>(null);
 62→  const [repostModal, setRepostModal] = useState<{journalId: string; title?: string; authorName?: string; authorAvatar?: string} | null>(null);
 63→  const [showRecap, setShowRecap] = useState(false);
 64→  const [recapData, setRecapData] = useState<WeeklyRecapData | null>(null);
 65→  const {query, setQuery, activeTab, setActiveTab, isSearching, normalizedQuery, users, journals} = useSearch();
 66→
 67→  const recapQuery = useQuery({
 68→    queryKey: ['weekly-recap'],
 69→    enabled: Boolean(token),
 70→    queryFn: () => analyticsApi.getWeeklyRecap(token),
 71→    staleTime: 60 * 60 * 1000,
 72→  });
 73→
 74→  useEffect(() => {
 75→    if (recapQuery.data?.recap?.available && !showRecap && !recapData) {
 76→      setRecapData(recapQuery.data.recap);
 77→      setShowRecap(true);
 78→    }
 79→  }, [recapQuery.data]);
 80→
 81→  const feedQuery = useInfiniteQuery({
 82→    queryKey: ['feed', user?.id],
 83→    enabled: feedTab === 'all',
 84→    queryFn: ({pageParam}) =>
 85→      mobileApi.getJournals(pageParam ?? null, PAGE_SIZE, user?.id),
 86→    initialPageParam: null as string | null,
 87→    getNextPageParam: lastPage => getNextCursor(lastPage, PAGE_SIZE),
 88→  });
 89→
 90→  const followingQuery = useInfiniteQuery({
 91→    queryKey: ['feed-following', user?.id],
 92→    enabled: feedTab === 'following' && Boolean(token),
 93→    queryFn: ({pageParam}) =>
 94→      mobileApi.getFollowingFeed(token, pageParam ?? null, PAGE_SIZE),
 95→    initialPageParam: null as string | null,
 96→    getNextPageParam: lastPage => getNextCursor(lastPage, PAGE_SIZE),
 97→  });
 98→
 99→  const forYouQuery = useInfiniteQuery({
100→    queryKey: ['feed-foryou', user?.id],
101→    enabled: feedTab === 'foryou' && Boolean(token),
102→    queryFn: ({pageParam}) =>
103→      mobileApi.getForYouFeed(token, (pageParam as number) ?? 0, PAGE_SIZE),
104→    initialPageParam: 0 as number,
105→    getNextPageParam: (lastPage, allPages) =>
106→      (lastPage.data?.length ?? 0) >= PAGE_SIZE ? allPages.length * PAGE_SIZE : undefined,
107→  });
108→
109→  const activeQuery = feedTab === 'following' ? followingQuery : feedTab === 'foryou' ? forYouQuery : feedQuery;
110→
111→  const reactionMutation = useMutation({
112→    mutationFn: async ({
113→      journalId,
114→      receiverId,
115→      reactionType,
116→    }: {
117→      journalId: string;
118→      receiverId: string;
119→      reactionType: string;
120→    }) => {
121→      if (!token) throw new Error('Please log in to react.');
122→      return socialApi.toggleReaction(token, {journalId, receiverId, reactionType});
123→    },
124→    onMutate: async ({journalId, reactionType}) => {
125→      await queryClient.cancelQueries({queryKey: ['feed']});
126→      const prev = queryClient.getQueryData<{pages: CursorPage<JournalItem>[]}>(
127→        ['feed', user?.id],
128→      );
129→      if (prev) {
130→        queryClient.setQueryData<{pages: CursorPage<JournalItem>[]}>(
131→          ['feed', user?.id],
132→          old => {
133→            if (!old) return old;
134→            return {
135→              ...old,
136→              pages: old.pages.map(page => ({
137→                ...page,
138→                data: page.data.map(item => {
139→                  if (item.id !== journalId) return item;
140→                  const removing = item.user_reaction === reactionType;
141→                  const currentCount =
142→                    (item.reaction_count?.[0]?.count ??
143→                      item.like_count?.[0]?.count ??
144→                      item.likes_count ??
145→                      0) as number;
146→                  const delta = removing ? -1 : item.user_reaction ? 0 : 1;
147→                  return {
148→                    ...item,
149→                    user_reaction: removing ? null : reactionType,
150→                    has_liked: removing ? false : true,
151→                    like_count: [{count: Math.max(0, currentCount + delta)}],
152→                  };
153→                }),
154→              })),
155→            };
156→          },
157→        );
158→      }
159→      return {prev};
160→    },
161→    onError: (_err, _vars, context) => {
162→      if (context?.prev) {
163→        queryClient.setQueryData(['feed', user?.id], context.prev);
164→      }
165→    },
166→    onSettled: () => {
167→      queryClient.invalidateQueries({queryKey: ['feed']});
168→    },
169→  });
170→
171→  const bookmarkMutation = useBookmarkMutation(token, ['feed', user?.id]);
172→
173→  const handleReact = (journalId: string, receiverId: string, reactionType: string) => {
174→    if (!token) return;
175→    reactionMutation.mutate({journalId, receiverId, reactionType});
176→  };
177→
178→  const handleComment = (journalId: string, receiverId?: string, commentCount?: number) => {
179→    setCommentModal({postId: journalId, receiverId, commentCount: commentCount ?? 0});
180→  };
181→
182→  const handleBookmark = (journalId: string) => {
183→    bookmarkMutation.mutate(journalId);
184→  };
185→
186→  const handleRepost = (journalId: string, title?: string, authorName?: string, authorAvatar?: string) => {
187→    setRepostModal({journalId, title, authorName, authorAvatar});
188→  };
189→
190→  const handleAuthorPress = (item: JournalItem) => {
191→    const authorId = item.users?.id ?? item.user_id;
192→    if (!authorId) return;
193→    if (authorId === user?.id) {
194→      navigation.navigate('Main' as any, {screen: 'Profile'});
195→    } else {
196→      navigation.navigate('VisitProfile', {
197→        userId: authorId,
198→        username: item.users?.username ?? undefined,
199→      });
200→    }
201→  };
202→
203→  const posts = useMemo(
204→    () => activeQuery.data?.pages.flatMap(page => page.data ?? []) ?? [],
205→    [activeQuery.data?.pages],
206→  );
207→
208→  const onRefresh = async () => {
209→    setRefreshing(true);
210→    try {
211→      await activeQuery.refetch();
212→    } finally {
213→      setRefreshing(false);
214→    }
215→  };
216→
217→  return (
218→    <SafeAreaView
219→      style={[styles.safe, {backgroundColor: colors.bgPrimary}]}
220→      edges={['top']}>
221→      {/* Branded header */}
222→      <View
223→        style={[
224→          styles.header,
225→          {borderBottomColor: colors.borderCard},
226→        ]}>
227→        <Text style={[styles.brandText, {color: colors.textHeading}]}>
228→          iskrib
229→        </Text>
230→        <SearchInput
231→          value={query}
232→          onChangeText={setQuery}
233→          placeholder="Search users or posts..."
234→          autoCapitalize="none"
235→          returnKeyType="search"
236→        />
237→      </View>
238→
239→      {isSearching ? (
240→        <SearchResultsView
241→          activeTab={activeTab}
242→          onTabChange={setActiveTab}
243→          users={users}
244→          journals={journals}
245→          normalizedQuery={normalizedQuery}
246→          onUserPress={(id, username) =>
247→            navigation.navigate('VisitProfile', {userId: id, username})
248→          }
249→          onPostPress={id =>
250→            navigation.navigate('PostDetail', {journalId: id})
251→          }
252→          onAuthorPress={handleAuthorPress}
253→          onReact={handleReact}
254→          onComment={handleComment}
255→          onBookmark={handleBookmark}
256→          onRepost={handleRepost}
257→          onEmbeddedPress={id =>
258→            navigation.navigate('PostDetail', {journalId: id})
259→          }
260→        />
261→      ) : (
262→        <>
263→          {/* Feed tab bar */}
264→          <FeedTabBar activeTab={feedTab} onTabChange={setFeedTab} />
265→
266→          {/* Feed */}
267→          <FlatList
268→            data={posts}
269→            onRefresh={onRefresh}
270→            refreshing={refreshing}
271→            onEndReachedThreshold={0.25}
272→            onEndReached={() => {
273→              if (activeQuery.hasNextPage && !activeQuery.isFetchingNextPage) {
274→                activeQuery.fetchNextPage();
275→              }
276→            }}
277→            contentContainerStyle={styles.listContent}
278→            showsVerticalScrollIndicator={false}
279→            ListHeaderComponent={
280→              feedTab === 'all' ? <DailyPromptCard onWrite={(promptId, promptText) => navigation.navigate('JournalEditor', {mode: 'create'})} /> : null
281→            }
282→            ListEmptyComponent={
283→              activeQuery.isLoading ? (
284→                <View style={styles.skeletonList}>
285→                  <PostCardSkeleton />
286→                  <PostCardSkeleton />
287→                  <PostCardSkeleton />
288→                </View>
289→              ) : (
290→                <EmptyState
291→                  title={feedTab === 'following' ? 'No posts from people you follow' : feedTab === 'foryou' ? 'No recommendations yet' : 'No posts yet'}
292→                  subtitle={feedTab === 'following' ? 'Follow writers to see their posts here.' : 'Pull to refresh or create your first journal post.'}
293→                />
294→              )
295→            }
296→            ListFooterComponent={
297→              activeQuery.isFetchingNextPage ? (
298→                <View style={styles.loadingMore}>
299→                  <PostCardSkeleton />
300→                </View>
301→              ) : null
302→            }
303→            keyExtractor={item => item.id}
304→            renderItem={({item}) => {
305→              const preview = extractPlainText(item.content).slice(0, 180);
306→              const likeCount = resolveCount(
307→                item.like_count,
308→                item.likes_count,
309→              );
310→              const commentCount = resolveCount(
311→                item.comment_count,
312→                item.comments_count,
313→              );
314→              const bookmarkCount = resolveCount(item.bookmark_count);
315→              const bannerImage = extractBannerImage(
316→                item.content,
317→                (item as any).images,
318→              );
319→
320→              const receiverId = item.user_id ?? item.users?.id ?? '';
321→
322→              const isRepost = !!item.is_repost;
323→              const repostSource = isRepost ? item.repost_source : null;
324→              const repostSourcePreview = repostSource?.preview_text || '';
325→
326→              return (
327→                <PostCard
328→                  title={item.title || 'Untitled Post'}
329→                  bodyPreview={preview || 'No preview text available.'}
330→                  authorName={item.users?.name || 'Unknown author'}
331→                  authorAvatar={item.users?.image_url}
332→                  authorBadge={item.users?.badge as 'legend' | 'og' | undefined}
333→                  bannerImage={bannerImage}
334→                  postType={item.post_type}
335→                  likeCount={likeCount}
336→                  commentCount={commentCount}
337→                  bookmarkCount={bookmarkCount}
338→                  userReaction={item.user_reaction}
339→                  isBookmarked={!!item.has_bookmarked}
340→                  onReact={type => handleReact(item.id, receiverId, type)}
341→                  onComment={() => handleComment(item.id, receiverId, commentCount)}
342→                  onBookmark={() => handleBookmark(item.id)}
343→                  onRepost={() => handleRepost(item.id, item.title ?? undefined, item.users?.name ?? undefined, item.users?.image_url ?? undefined)}
344→                  onPress={() =>
345→                    navigation.navigate('PostDetail', {journalId: item.id})
346→                  }
347→                  onAuthorPress={() => handleAuthorPress(item)}
348→                  isRepost={isRepost}
349→                  repostCaption={item.repost_caption}
350→                  repostSourceTitle={repostSource?.title}
351→                  repostSourcePreview={repostSourcePreview}
352→                  repostSourceAuthorName={repostSource?.users?.name}
353→                  repostSourceAuthorAvatar={repostSource?.users?.image_url}
354→                  onEmbeddedPress={repostSource ? () => navigation.navigate('PostDetail', {journalId: repostSource.id}) : undefined}
355→                />
356→              );
357→            }}
358→            ItemSeparatorComponent={() => <View style={styles.separator} />}
359→          />
360→        </>
361→      )}
362→
363→      {commentModal && (
364→        <CommentModal
365→          visible
366→          postId={commentModal.postId}
367→          receiverId={commentModal.receiverId}
368→          commentCount={commentModal.commentCount}
