376→
377→    const lexicalPayload = {
378→      root: {
379→        children: [
380→          {
381→            type: 'paragraph',
382→            children: [
383→              {
384→                type: 'text',
385→                text: payload.plainText,
386→                detail: 0,
387→                format: 0,
388→                mode: 'normal',
389→                style: '',
390→                version: 1,
391→              },
392→            ],
393→            direction: null,
394→            format: '',
395→            indent: 0,
396→            version: 1,
397→          },
398→        ],
399→        direction: null,
400→        format: '',
401→        indent: 0,
402→        type: 'root',
403→        version: 1,
404→      },
405→    };
406→
407→    formData.append('title', payload.title);
408→    formData.append('content', JSON.stringify(lexicalPayload));
409→    formData.append('post_type', 'text');
410→    if (payload.privacy) {
411→      formData.append('privacy', payload.privacy);
412→    }
413→
414→    return apiRequest<{ message?: string }>('/save-journal', {
415→      method: 'POST',
416→      headers: {
417→        ...authHeaders(token),
418→      },
419→      body: formData,
420→      timeoutMs: 30000,
421→      retries: 0,
422→    });
423→  },
