 49→const getHotScore = (journal: JournalItem): number => {
 50→  if (typeof journal.hot_score === 'number') return journal.hot_score;
 51→  const likes = resolveCount(journal.like_count, journal.likes_count);
 52→  const comments = resolveCount(journal.comment_count, journal.comments_count);
 53→  const bookmarks = resolveCount(journal.bookmark_count);
 54→  return likes + comments * 2 + bookmarks * 3;
 55→};
